public interface INotifier {
  string Send(string message);
}

public class EmailNotifier : INotifier {
  public string Send(string message) => "email:" + message;
}

public class SmsNotifier : INotifier {
  public string Send(string message) => "sms:" + message;
}

public abstract class NotifierFactory {
  public abstract INotifier Create();
}

public class EmailNotifierFactory : NotifierFactory {
  public override INotifier Create() => new EmailNotifier();
}

public class SmsNotifierFactory : NotifierFactory {
  public override INotifier Create() => new SmsNotifier();
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Create_ReturnsEmailNotifier() {
  NotifierFactory factory = new EmailNotifierFactory();
  var notifier = factory.Create();
  Assert.AreEqual("email:test", notifier.Send("test"));
}

[TestMethod]
public void Create_ReturnsSmsNotifier() {
  NotifierFactory factory = new SmsNotifierFactory();
  var notifier = factory.Create();
  Assert.AreEqual("sms:test", notifier.Send("test"));
}
